     1→#!/usr/bin/env node
     2→/**
     3→ * End-to-End Testing CLI Tool (T036k)
     4→ *
     5→ * Simple CLI for manual end-to-end testing of classification pipeline.
     6→ * Supports single email, batch, and date-range processing modes.
     7→ *
     8→ * Usage:
     9→ *   npm run test:pipeline -- --mode single --message-id <id>
    10→ *   npm run test:pipeline -- --mode batch --limit 10
    11→ *   npm run test:pipeline -- --mode date-range --start 2025-09-01 --end 2025-09-30 --limit 50
    12→ *   npm run test:pipeline -- --dry-run  # Classify without persisting
    13→ *
    14→ * Output:
    15→ *   - Per-email: [message_id] subject → labels: [label1, label2] (confidence: 0.85) - 8.3s
    16→ *   - Summary: Processed 10 emails in 83.5s (avg 8.35s/email), 9 success, 1 error
    17→ *   - Explainability traces: ./test-pipeline-results/<timestamp>/<message_id>.json
    18→ */
    19→
    20→import { promises as fs } from 'fs';
    21→import { join, dirname } from 'path';
    22→import {
    23→  fetchEmailById,
    24→  fetchUnclassifiedEmails,
    25→  fetchEmailsByDateRange,
    26→  closePool as closeQueryPool,
    27→} from '../persistence/email-query';
    28→import { saveClassificationResult, closePool as closeWriterPool } from '../persistence/classification-writer';
    29→import {
    30→  ClassificationPipeline,
    31→  ConfigurationLoader,
    32→  ClassificationPipelineError,
    33→  createClassificationSession,
    34→  incrementSessionSuccess,
    35→  incrementSessionError,
    36→  finalizeClassificationSession,
    37→  type CategoryConfiguration,
    38→  type EmailMessage,
    39→  type ClassificationResult,
    40→  type SelectedLabel,
    41→} from '@gmail-automation/classification-engine';
    42→import { ConsoleInterceptor } from './console-interceptor';
    43→
    44→/**
    45→ * CLI argument structure
    46→ */
    47→export interface CLIArguments {
    48→  mode: 'single' | 'batch' | 'date-range' | 'replay' | 'replay-from';
    49→  messageId?: string;
    50→  limit?: number;
    51→  startDate?: string;
    52→  endDate?: string;
    53→  dryRun: boolean;
    54→  replayFrom?: string;
    55→  sessionId?: string;
    56→}
    57→
    58→/**
    59→ * Processing summary statistics
    60→ */
    61→export interface ProcessingSummary {
    62→  totalEmails: number;
    63→  success: number;
    64→  errors: number;
    65→  totalDurationMs: number;
    66→  errorDetails: Array<{ messageId: string; error: string }>;
    67→}
    68→
    69→/**
    70→ * Find the monorepo root directory by searching upward for package.json with workspaces
    71→ *
    72→ * @param startDir - Directory to start searching from (defaults to current working directory)
    73→ * @returns Path to monorepo root directory
    74→ * @throws Error if monorepo root cannot be found
    75→ */
    76→export async function findRepoRoot(startDir: string = process.cwd()): Promise<string> {
    77→  let currentDir = startDir;
    78→  const root = '/';
    79→
    80→  while (currentDir !== root) {
    81→    try {
    82→      const packageJsonPath = join(currentDir, 'package.json');
    83→      const packageJsonContent = await fs.readFile(packageJsonPath, 'utf-8');
    84→      const packageJson = JSON.parse(packageJsonContent);
    85→
    86→      // Check if this package.json has workspaces field (indicates monorepo root)
    87→      if (packageJson.workspaces) {
    88→        return currentDir;
    89→      }
    90→    } catch {
    91→      // package.json not found or not readable, continue searching
    92→    }
    93→
    94→    // Move up one directory
    95→    currentDir = dirname(currentDir);
    96→  }
    97→
    98→  throw new Error('Could not find monorepo root (package.json with workspaces field)');
    99→}
   100→
   101→/**
   102→ * Display help message
   103→ */
   104→function displayHelp(): void {
   105→  console.log(`
   106→End-to-End Classification Pipeline Testing Tool
   107→
   108→Usage:
   109→  npm run test:pipeline -- --mode <mode> [options]
   110→
   111→Modes:
   112→  single       Process a single email by message ID
   113→  batch        Process multiple unclassified emails
   114→  date-range   Process emails within a date range
   115→  replay       Re-run full pipeline with session data (useful for configuration tuning)
   116→  replay-from  Replay pipeline from a specific stage using session data (advanced debugging)
   117→
   118→Options:
   119→  --mode <mode>           Required: single, batch, date-range, replay, or replay-from
   120→  --message-id <id>       Required for single mode: Gmail message ID
   121→  --limit <number>        Optional: Maximum emails to process (default: 10 for batch, 100 for date-range)
   122→  --start <YYYY-MM-DD>    Required for date-range: Start date
   123→  --end <YYYY-MM-DD>      Required for date-range: End date
   124→  --session-id <sessionId> Required for replay/replay-from modes: Session ID containing trace data
   125→  --replay-from <stage>   Required for replay-from mode: Stage to start from (e.g., ai-routing, rule-scoring)
   126→  --dry-run               Optional: Classify without persisting to database
   127→  --help                  Display this help message
   128→
   129→Examples:
   130→  # Single email
   131→  npm run test:pipeline -- --mode single --message-id 18f2a3b4c5d6e7f8
   132→
   133→  # Batch processing
   134→  npm run test:pipeline -- --mode batch --limit 10
   135→
   136→  # Date range
   137→  npm run test:pipeline -- --mode date-range --start 2025-09-01 --end 2025-09-30 --limit 50
   138→
   139→  # Dry run (no database writes)
   140→  npm run test:pipeline -- --mode batch --limit 5 --dry-run
   141→
   142→  # Full replay (re-run complete pipeline with session data)
   143→  npm run test:pipeline -- --mode replay --session-id 2025-10-04T10-30-45-123Z
   144→
   145→  # Advanced: Replay from AI routing stage (useful for tuning AI prompts)
   146→  npm run test:pipeline -- --mode replay-from --replay-from ai-routing --session-id 2025-10-04T10-30-45-123Z
   147→
   148→  # Advanced: Replay from rule scoring (useful for tuning scoring rules)
   149→  npm run test:pipeline -- --mode replay-from --replay-from rule-scoring --session-id 2025-10-04T10-30-45-123Z
   150→
   151→Output:
   152→  - Per-email results with labels, confidence, and processing time
   153→  - Summary statistics (total, success, errors, average time)
   154→  - Explainability traces in ./test-pipeline-results/<sessionId>/
   155→
   156→Configuration:
   157→  - Config files automatically located in repo root config/
   158→  - Database connection from environment variables
   159→  - Build classification-engine before first run: npm run build --workspace=packages/classification-engine
   160→`);
   161→}
   162→
   163→/**
   164→ * Parse command line arguments
   165→ *
   166→ * @param args - Process arguments (excluding node and script path)
   167→ * @returns Parsed CLI arguments
   168→ * @throws Error if required arguments missing or invalid
   169→ */
   170→export function parseArguments(args: string[]): CLIArguments {
   171→  // Check for help flag first
   172→  if (args.includes('--help') || args.includes('-h')) {
   173→    displayHelp();
   174→    process.exit(0);
   175→  }
   176→
   177→  const result: Partial<CLIArguments> = {
   178→    dryRun: false,
   179→  };
   180→
   181→  for (let i = 0; i < args.length; i++) {
   182→    const arg = args[i];
   183→
   184→    switch (arg) {
   185→      case '--mode':
   186→        if (i + 1 >= args.length) {
   187→          throw new Error('Missing value for --mode argument');
   188→        }
   189→        result.mode = args[++i] as 'single' | 'batch' | 'date-range' | 'replay' | 'replay-from';
   190→        break;
   191→      case '--message-id':
   192→        if (i + 1 >= args.length) {
   193→          throw new Error('Missing value for --message-id argument');
   194→        }
   195→        result.messageId = args[++i];
   196→        break;
   197→      case '--limit':
   198→        if (i + 1 >= args.length) {
   199→          throw new Error('Missing value for --limit argument');
   200→        }
   201→        result.limit = parseInt(args[++i], 10);
   202→        break;
   203→      case '--start':
   204→        if (i + 1 >= args.length) {
   205→          throw new Error('Missing value for --start argument');
   206→        }
   207→        result.startDate = args[++i];
   208→        break;
   209→      case '--end':
   210→        if (i + 1 >= args.length) {
   211→          throw new Error('Missing value for --end argument');
   212→        }
   213→        result.endDate = args[++i];
   214→        break;
   215→      case '--dry-run':
   216→        result.dryRun = true;
   217→        break;
   218→      case '--replay-from':
   219→        if (i + 1 >= args.length) {
   220→          throw new Error('Missing value for --replay-from argument');
   221→        }
   222→        result.replayFrom = args[++i];
   223→        break;
   224→      case '--session-id':
   225→        if (i + 1 >= args.length) {
   226→          throw new Error('Missing value for --session-id argument');
   227→        }
   228→        result.sessionId = args[++i];
   229→        break;
   230→    }
   231→  }
   232→
   233→  // Validate required arguments
   234→  if (!result.mode) {
   235→    throw new Error('Mode is required (--mode single|batch|date-range|replay|replay-from)');
   236→  }
   237→
   238→  if (!['single', 'batch', 'date-range', 'replay', 'replay-from'].includes(result.mode)) {
   239→    throw new Error('Invalid mode. Must be: single, batch, date-range, replay, or replay-from');
   240→  }
   241→
   242→  if (result.mode === 'single' && !result.messageId) {
   243→    throw new Error('message-id is required for single mode (--message-id <id>)');
   244→  }
   245→
   246→  if (result.mode === 'replay') {
   247→    if (!result.sessionId) {
   248→      throw new Error('--session-id <sessionId> is required for replay mode');
   249→    }
   250→  }
   251→
   252→  if (result.mode === 'replay-from') {
   253→    if (!result.replayFrom || !result.sessionId) {
   254→      throw new Error('Both --replay-from <stage> and --session-id <sessionId> are required for replay-from mode');
   255→    }
   256→  }
   257→
   258→  if (result.mode === 'date-range') {
   259→    if (!result.startDate || !result.endDate) {
   260→      throw new Error(
   261→        'Both start and end dates are required for date-range mode (--start YYYY-MM-DD --end YYYY-MM-DD)'
   262→      );
   263→    }
   264→  }
   265→
   266→  return result as CLIArguments;
   267→}
   268→
   269→/**
   270→ * Load configuration from config directory
   271→ *
   272→ * @returns Loaded category configuration
   273→ * @throws Error if configuration loading fails
   274→ */
   275→async function loadConfiguration(): Promise<CategoryConfiguration> {
   276→  // Find monorepo root to locate config directory
   277→  const repoRoot = await findRepoRoot();
   278→
   279→  const configLoader = new ConfigurationLoader({
   280→    configDir: join(repoRoot, 'config'),
   281→    enableHotReload: false,
   282→    validateOnLoad: true,
   283→  });
   284→
   285→  const categoryConfigResult = await configLoader.loadCategoryConfiguration();
   286→
   287→  if (!categoryConfigResult.validationPassed) {
   288→    throw new Error(`Configuration validation failed:\n${categoryConfigResult.validationErrors.join('\n')}`);
   289→  }
   290→
   291→  // Validate config exists before type assertion
   292→  if (!categoryConfigResult.config) {
   293→    throw new Error('Configuration loading returned empty config');
   294→  }
   295→
   296→  // Return full CategoryConfiguration
   297→  // Use safe type assertion pattern as config loader returns runtime-validated configuration
   298→  const config = categoryConfigResult.config as unknown as CategoryConfiguration;
   299→  if (!config.processingConfig) {
   300→    throw new Error('Missing processingConfig in category configuration');
   301→  }
   302→
   303→  return config;
   304→}
   305→
   306→/**
   307→ * Process single email through classification pipeline
   308→ *
   309→ * @param messageId - Gmail message ID
   310→ * @param config - Category configuration
   311→ * @param dryRun - If true, skip persistence
   312→ * @returns Processing summary
   313→ */
   314→export async function processSingleEmail(
   315→  messageId: string,
   316→  config: CategoryConfiguration,
   317→  dryRun: boolean
   318→): Promise<ProcessingSummary> {
   319→  const summary: ProcessingSummary = {
   320→    totalEmails: 1,
   321→    success: 0,
   322→    errors: 0,
   323→    totalDurationMs: 0,
   324→    errorDetails: [],
   325→  };
   326→
   327→  const startTime = Date.now();
   328→
   329→  // 1. Fetch email from database
   330→  console.log(`Fetching email: ${messageId}`);
   331→  const email = await fetchEmailById(messageId);
