   636→export function formatEmailOutput(email: EmailMessage, result: ClassificationResult): string {
   637→  const labels = result.selectedLabels.map((label: SelectedLabel) => label.subtype || label.category).join(', ');
   638→  const primaryLabel = result.selectedLabels.find((l: SelectedLabel) => l.isPrimary);
   639→  const confidence = primaryLabel ? primaryLabel.confidence.toFixed(2) : '0.00';
   640→  const durationSec = (result.processingDurationMs / 1000).toFixed(1);
