   716→/**
   717→ * Pipeline stage mapping for replay functionality
   718→ */
   719→const STAGE_ORDER = [
   720→  'hard-assertions',
   721→  'strong-indicators',
   722→  'rule-scoring',
   723→  'attribute-detection',
   724→  'attribute-influence',
   725→  'disambiguation',
   726→  'multi-label-selection',
   727→  'ai-routing',
   728→  'ai-feature-extraction',
   729→  'ai-classification',
   730→  'ai-label-filtering',
   731→  'action-determination',
   732→] as const;
   733→
   734→type PipelineStage = (typeof STAGE_ORDER)[number];
   735→
   736→/**
   737→ * Load trace data from session directory and validate stage availability
   738→ *
   739→ * @param sessionId - Session ID to load traces from
   740→ * @param replayFromStage - Stage to start replay from
   741→ * @returns Array of trace data with email messages and classification results
   742→ */
   743→async function loadSessionTraces(
   744→  sessionId: string,
   745→  replayFromStage: PipelineStage
   746→): Promise<Array<{ email: EmailMessage; result: ClassificationResult; tracePath: string }>> {
   747→  const repoRoot = await findRepoRoot();
   748→  const sessionDir = join(repoRoot, 'test-pipeline-results', sessionId);
   749→
   750→  // Check if session directory exists
   751→  try {
   752→    await fs.access(sessionDir);
   753→  } catch {
   754→    throw new Error(`Session directory not found: ${sessionDir}. Please check the session ID.`);
   755→  }
   756→
   757→  // Get all trace files in the session
   758→  const files = await fs.readdir(sessionDir);
   759→  const traceFiles = files.filter((f) => f.endsWith('.json'));
   760→
   761→  if (traceFiles.length === 0) {
   762→    throw new Error(`No trace files found in session ${sessionId}`);
   763→  }
   764→
   765→  console.log(`Found ${traceFiles.length} trace files in session ${sessionId}`);
   766→
   767→  // Load and validate each trace
   768→  const traces: Array<{ email: EmailMessage; result: ClassificationResult; tracePath: string }> = [];
   769→
   770→  for (const file of traceFiles) {
   771→    const tracePath = join(sessionDir, file);
   772→
   773→    try {
   774→      const traceContent = await fs.readFile(tracePath, 'utf-8');
   775→      const trace = JSON.parse(traceContent);
   776→
   777→      if (!trace.classificationResult || !trace.messageId) {
   778→        console.warn(`Skipping invalid trace file: ${file}`);
   779→        continue;
   780→      }
   781→
   782→      // Validate that we have enough stage data to replay from the requested stage
   783→      const stageIndex = STAGE_ORDER.indexOf(replayFromStage);
   784→      if (stageIndex === -1) {
   785→        throw new Error(`Invalid stage: ${replayFromStage}. Valid stages: ${STAGE_ORDER.join(', ')}`);
   786→      }
   787→
   788→      // Check that all prior stages have been executed (basic validation)
   789→      const explainabilityTrace = trace.classificationResult.explainabilityTrace;
   790→      const requiredStages = STAGE_ORDER.slice(0, stageIndex);
   791→
   792→      for (const stage of requiredStages) {
   793→        // Map stage names to explainability trace properties
   794→        const hasStageData = getStageData(explainabilityTrace, stage);
   795→        if (!hasStageData) {
   796→          throw new Error(
   797→            `Missing required stage data for ${stage} in ${file}. Cannot replay from ${replayFromStage}.`
   798→          );
   799→        }
   800→      }
   801→
   802→      // Reconstruct email message from trace
   803→      const email: EmailMessage = {
   804→        id: trace.messageId,
   805→        threadId: '',
   806→        gmailLabels: [],
   807→        payload: {
   808→          mimeType: 'text/plain',
   809→          headers: [],
   810→          body: { data: '', size: 0 },
   811→        },
   812→        subject: trace.subject,
   813→        from: { email: trace.from, name: '', raw: trace.from },
   814→        to: [],
   815→        date: new Date(trace.date),
   816→        bodyPlain: trace.classificationResult.bodyContent || '',
   817→        isProcessed: false,
   818→        processingPriority: 0,
   819→      };
   820→
   821→      traces.push({
   822→        email,
   823→        result: trace.classificationResult,
   824→        tracePath,
   825→      });
   826→    } catch (error) {
   827→      console.warn(`Error loading trace file ${file}:`, error instanceof Error ? error.message : String(error));
   828→    }
   829→  }
   830→
   831→  if (traces.length === 0) {
   832→    throw new Error(`No valid trace files found in session ${sessionId}`);
   833→  }
   834→
   835→  console.log(`Successfully loaded ${traces.length} valid traces for replay from ${replayFromStage}`);
   836→  return traces;
   837→}
   838→
   839→/**
   840→ * Check if stage data exists in explainability trace
   841→ */
   842→function getStageData(trace: unknown, stage: PipelineStage): boolean {
   843→  const traceObj = trace as Record<string, unknown>;
   844→  switch (stage) {
   845→    case 'hard-assertions':
   846→      return Array.isArray(traceObj.hardAssertions) && (traceObj.hardAssertions as unknown[]).length >= 0;
   847→    case 'strong-indicators':
   848→      return Array.isArray(traceObj.strongIndicators) && (traceObj.strongIndicators as unknown[]).length >= 0;
   849→    case 'rule-scoring':
   850→      return Array.isArray(traceObj.ruleScoring) && (traceObj.ruleScoring as unknown[]).length >= 0;
   851→    case 'attribute-detection':
   852→      return Array.isArray(traceObj.attributeDetection) && (traceObj.attributeDetection as unknown[]).length >= 0;
   853→    case 'attribute-influence':
   854→      return Array.isArray(traceObj.attributeInfluence) && (traceObj.attributeInfluence as unknown[]).length >= 0;
   855→    case 'disambiguation':
   856→      return Array.isArray(traceObj.disambiguation) && (traceObj.disambiguation as unknown[]).length >= 0;
   857→    case 'multi-label-selection':
   858→      return Array.isArray(traceObj.multiLabelSelection) && (traceObj.multiLabelSelection as unknown[]).length >= 0;
   859→    case 'ai-routing':
   860→      return traceObj.aiRouting !== undefined;
   861→    case 'ai-feature-extraction':
   862→    case 'ai-classification':
   863→    case 'ai-label-filtering':
   864→    case 'action-determination':
   865→      return true; // These stages can always be replayed
   866→    default:
   867→      return false;
   868→  }
   869→}
