   928→          messageId: email.id,
   929→          error: error instanceof Error ? error.message : String(error),
   930→        });
   931→
   932→        console.error(`Error replaying ${email.id}: ${error instanceof Error ? error.message : String(error)}`);
   933→
   934→        // Write trace with error information and partial result (if available)
   935→        const tempSessionId = new Date().toISOString().replace(/[:.]/g, '-').slice(0, -5) + 'Z';
   936→        const partialResult = error instanceof ClassificationPipelineError ? error.partialResult : undefined;
   937→        await writeExplainabilityTrace(
   938→          email,
   939→          tempSessionId,
   940→          partialResult,
   941→          error instanceof Error ? error : new Error(String(error))
   942→        );
