/**
 * Console Interceptor
 *
 * Temporarily intercepts console output and writes to both console and file.
 * Used to capture all pipeline logging output on a per-email basis.
 */

import { promises as fs } from 'fs';

/**
 * Console interceptor that writes to both original console and a file
 */
export class ConsoleInterceptor {
  private originalConsole: {
    log: typeof console.log;
    error: typeof console.error;
    warn: typeof console.warn;
  };
  private logBuffer: string[] = [];
  private isActive: boolean = false;
  private logFilePath: string;

  constructor(logFilePath: string) {
    this.logFilePath = logFilePath;
    this.originalConsole = {
      log: console.log,
      error: console.error,
      warn: console.warn,
    };
  }

  /**
   * Start intercepting console output
   */
  start(): void {
    if (this.isActive) {
      return;
    }

    this.isActive = true;
    this.logBuffer = [];

    // Override console methods
    console.log = (...args: unknown[]) => {
      const message = args.map((arg) => String(arg)).join(' ');
      this.logBuffer.push(`[INFO] ${message}\n`);
      this.originalConsole.log(...args);
    };

    console.error = (...args: unknown[]) => {
      const message = args.map((arg) => String(arg)).join(' ');
      this.logBuffer.push(`[ERROR] ${message}\n`);
      this.originalConsole.error(...args);
    };

    console.warn = (...args: unknown[]) => {
      const message = args.map((arg) => String(arg)).join(' ');
      this.logBuffer.push(`[WARN] ${message}\n`);
      this.originalConsole.warn(...args);
    };
  }

  /**
   * Stop intercepting and restore original console
   */
  stop(): void {
    if (!this.isActive) {
      return;
    }

    console.log = this.originalConsole.log;
    console.error = this.originalConsole.error;
    console.warn = this.originalConsole.warn;
    this.isActive = false;
  }

  /**
   * Flush captured logs to file
   */
  async flush(): Promise<void> {
    if (this.logBuffer.length === 0) {
      return;
    }

    const content = this.logBuffer.join('');
    await fs.appendFile(this.logFilePath, content);
    this.logBuffer = [];
  }

  /**
   * Stop intercepting and flush logs to file
   */
  async close(): Promise<void> {
    this.stop();
    await this.flush();
  }
}

