#!/usr/bin/env node
/**
 * End-to-End Testing CLI Tool (T036k)
 *
 * Simple CLI for manual end-to-end testing of classification pipeline.
 * Supports single email, batch, and date-range processing modes.
 *
 * Usage:
 *   npm run test:pipeline -- --mode single --message-id <id>
 *   npm run test:pipeline -- --mode batch --limit 10
 *   npm run test:pipeline -- --mode date-range --start 2025-09-01 --end 2025-09-30 --limit 50
 *   npm run test:pipeline -- --dry-run  # Classify without persisting
 *
 * Output:
 *   - Per-email: [message_id] subject → labels: [label1, label2] (confidence: 0.85) - 8.3s
 *   - Summary: Processed 10 emails in 83.5s (avg 8.35s/email), 9 success, 1 error
 *   - Explainability traces: ./test-pipeline-results/<timestamp>/<message_id>.json
 */

import { promises as fs } from 'fs';
import { join, dirname } from 'path';
import {
  fetchEmailById,
  fetchUnclassifiedEmails,
  fetchEmailsByDateRange,
  closePool as closeQueryPool,
} from '../persistence/email-query';
import { saveClassificationResult, closePool as closeWriterPool } from '../persistence/classification-writer';
import {
  ClassificationPipeline,
  ConfigurationLoader,
  ClassificationPipelineError,
  createClassificationSession,
  incrementSessionSuccess,
  incrementSessionError,
  finalizeClassificationSession,
  type CategoryConfiguration,
  type EmailMessage,
  type ClassificationResult,
  type SelectedLabel,
} from '@gmail-automation/classification-engine';
import { createLogger } from '../logging/logger-factory';

// Logger for diagnostic traces (controlled via LOG_LEVEL environment variable)
const logger = createLogger({ prettyPrint: true });

/**
 * CLI argument structure
 */
export interface CLIArguments {
  mode: 'single' | 'batch' | 'date-range' | 'replay' | 'replay-from';
  messageId?: string;
  limit?: number;
  startDate?: string;
  endDate?: string;
  dryRun: boolean;
  replayFrom?: string;
  sessionId?: string;
}

/**
 * Processing summary statistics
 */
export interface ProcessingSummary {
  totalEmails: number;
  success: number;
  errors: number;
  totalDurationMs: number;
  errorDetails: Array<{ messageId: string; error: string }>;
}

/**
 * Find the monorepo root directory by searching upward for package.json with workspaces
 *
 * @param startDir - Directory to start searching from (defaults to current working directory)
 * @returns Path to monorepo root directory
 * @throws Error if monorepo root cannot be found
 */
export async function findRepoRoot(startDir: string = process.cwd()): Promise<string> {
  let currentDir = startDir;
  const root = '/';

  while (currentDir !== root) {
    try {
      const packageJsonPath = join(currentDir, 'package.json');
      const packageJsonContent = await fs.readFile(packageJsonPath, 'utf-8');
      const packageJson = JSON.parse(packageJsonContent);

      // Check if this package.json has workspaces field (indicates monorepo root)
      if (packageJson.workspaces) {
        return currentDir;
      }
    } catch {
      // package.json not found or not readable, continue searching
    }

    // Move up one directory
    currentDir = dirname(currentDir);
  }

  throw new Error('Could not find monorepo root (package.json with workspaces field)');
}

/**
 * Display help message
 */
function displayHelp(): void {
  console.log(`
End-to-End Classification Pipeline Testing Tool

Usage:
  npm run test:pipeline -- --mode <mode> [options]

Modes:
  single       Process a single email by message ID
  batch        Process multiple unclassified emails
  date-range   Process emails within a date range
  replay       Re-run full pipeline with session data (useful for configuration tuning)
  replay-from  Replay pipeline from a specific stage using session data (advanced debugging)

Options:
  --mode <mode>           Required: single, batch, date-range, replay, or replay-from
  --message-id <id>       Required for single mode: Gmail message ID
  --limit <number>        Optional: Maximum emails to process (default: 10 for batch, 100 for date-range)
  --start <YYYY-MM-DD>    Required for date-range: Start date
  --end <YYYY-MM-DD>      Required for date-range: End date
  --session-id <sessionId> Required for replay/replay-from modes: Session ID containing trace data
  --replay-from <stage>   Required for replay-from mode: Stage to start from (e.g., ai-routing, rule-scoring)
  --dry-run               Optional: Classify without persisting to database
  --help                  Display this help message

Examples:
  # Single email
  npm run test:pipeline -- --mode single --message-id 18f2a3b4c5d6e7f8

  # Batch processing
  npm run test:pipeline -- --mode batch --limit 10

  # Date range
  npm run test:pipeline -- --mode date-range --start 2025-09-01 --end 2025-09-30 --limit 50

  # Dry run (no database writes)
  npm run test:pipeline -- --mode batch --limit 5 --dry-run

  # Full replay (re-run complete pipeline with session data)
  npm run test:pipeline -- --mode replay --session-id 2025-10-04T10-30-45-123Z

  # Advanced: Replay from AI routing stage (useful for tuning AI prompts)
  npm run test:pipeline -- --mode replay-from --replay-from ai-routing --session-id 2025-10-04T10-30-45-123Z

  # Advanced: Replay from rule scoring (useful for tuning scoring rules)
  npm run test:pipeline -- --mode replay-from --replay-from rule-scoring --session-id 2025-10-04T10-30-45-123Z

Output:
  - Per-email results with labels, confidence, and processing time
  - Summary statistics (total, success, errors, average time)
  - Explainability traces in ./test-pipeline-results/<sessionId>/

Configuration:
  - Config files automatically located in repo root config/
  - Database connection from environment variables
  - Build classification-engine before first run: npm run build --workspace=packages/classification-engine
`);
}

/**
 * Parse command line arguments
 *
 * @param args - Process arguments (excluding node and script path)
 * @returns Parsed CLI arguments
 * @throws Error if required arguments missing or invalid
 */
export function parseArguments(args: string[]): CLIArguments {
  // Check for help flag first
  if (args.includes('--help') || args.includes('-h')) {
    displayHelp();
    process.exit(0);
  }

  const result: Partial<CLIArguments> = {
    dryRun: false,
  };

  for (let i = 0; i < args.length; i++) {
    const arg = args[i];

    switch (arg) {
      case '--mode':
        if (i + 1 >= args.length) {
          throw new Error('Missing value for --mode argument');
        }
        result.mode = args[++i] as 'single' | 'batch' | 'date-range' | 'replay' | 'replay-from';
        break;
      case '--message-id':
        if (i + 1 >= args.length) {
          throw new Error('Missing value for --message-id argument');
        }
        result.messageId = args[++i];
        break;
      case '--limit':
        if (i + 1 >= args.length) {
          throw new Error('Missing value for --limit argument');
        }
        result.limit = parseInt(args[++i], 10);
        break;
      case '--start':
        if (i + 1 >= args.length) {
          throw new Error('Missing value for --start argument');
        }
        result.startDate = args[++i];
        break;
      case '--end':
        if (i + 1 >= args.length) {
          throw new Error('Missing value for --end argument');
        }
        result.endDate = args[++i];
        break;
      case '--dry-run':
        result.dryRun = true;
        break;
      case '--replay-from':
        if (i + 1 >= args.length) {
          throw new Error('Missing value for --replay-from argument');
        }
        result.replayFrom = args[++i];
        break;
      case '--session-id':
        if (i + 1 >= args.length) {
          throw new Error('Missing value for --session-id argument');
        }
        result.sessionId = args[++i];
        break;
    }
  }

  // Validate required arguments
  if (!result.mode) {
    throw new Error('Mode is required (--mode single|batch|date-range|replay|replay-from)');
  }

  if (!['single', 'batch', 'date-range', 'replay', 'replay-from'].includes(result.mode)) {
    throw new Error('Invalid mode. Must be: single, batch, date-range, replay, or replay-from');
  }

  if (result.mode === 'single' && !result.messageId) {
    throw new Error('message-id is required for single mode (--message-id <id>)');
  }

  if (result.mode === 'replay') {
    if (!result.sessionId) {
      throw new Error('--session-id <sessionId> is required for replay mode');
    }
  }

  if (result.mode === 'replay-from') {
    if (!result.replayFrom || !result.sessionId) {
      throw new Error('Both --replay-from <stage> and --session-id <sessionId> are required for replay-from mode');
    }
  }

  if (result.mode === 'date-range') {
    if (!result.startDate || !result.endDate) {
      throw new Error(
        'Both start and end dates are required for date-range mode (--start YYYY-MM-DD --end YYYY-MM-DD)'
      );
    }
  }

  return result as CLIArguments;
}

/**
 * Load configuration from config directory
 *
 * @returns Loaded category configuration
 * @throws Error if configuration loading fails
 */
async function loadConfiguration(): Promise<CategoryConfiguration> {
  // Find monorepo root to locate config directory
  const repoRoot = await findRepoRoot();

  const configLoader = new ConfigurationLoader({
    configDir: join(repoRoot, 'config'),
    enableHotReload: false,
    validateOnLoad: true,
  });

  const categoryConfigResult = await configLoader.loadCategoryConfiguration();

  if (!categoryConfigResult.validationPassed) {
    throw new Error(`Configuration validation failed:\n${categoryConfigResult.validationErrors.join('\n')}`);
  }

  // Validate config exists before type assertion
  if (!categoryConfigResult.config) {
    throw new Error('Configuration loading returned empty config');
  }

  // Return full CategoryConfiguration
  // Use safe type assertion pattern as config loader returns runtime-validated configuration
  const config = categoryConfigResult.config as unknown as CategoryConfiguration;
  if (!config.processingConfig) {
    throw new Error('Missing processingConfig in category configuration');
  }

  return config;
}

/**
 * Process single email through classification pipeline
 *
 * @param messageId - Gmail message ID
 * @param config - Category configuration
 * @param dryRun - If true, skip persistence
 * @returns Processing summary
 */
export async function processSingleEmail(
  messageId: string,
  config: CategoryConfiguration,
  dryRun: boolean
): Promise<ProcessingSummary> {
  const summary: ProcessingSummary = {
    totalEmails: 1,
    success: 0,
    errors: 0,
    totalDurationMs: 0,
    errorDetails: [],
  };

  const startTime = Date.now();

  // 1. Fetch email from database
  logger.debug({ messageId }, 'Fetching email');
  const email = await fetchEmailById(messageId);

  // 2. Initialize pipeline with test mode enabled
  const pipeline = new ClassificationPipeline(config, true);

  // 3. Create session directory for explainability traces
  const repoRoot = await findRepoRoot();
  const tempSessionId = new Date().toISOString().replace(/[:.]/g, '-').slice(0, -5) + 'Z';
  const sessionDir = join(repoRoot, 'test-pipeline-results', tempSessionId);
  await fs.mkdir(sessionDir, { recursive: true });

  try {
    // 5. Classify email
    logger.debug({ emailId: email.id, subject: email.subject }, 'Classifying email');
    const result = await pipeline.classify(email);

    // 6. Output result
    console.log(formatEmailOutput(email, result));

    // 7. Persist result (unless dry-run)
    if (!dryRun) {
      await saveClassificationResult(messageId, result);
      logger.debug({ messageId }, 'Persisted classification result');
    } else {
      console.log(`[DRY RUN] Skipped persistence for ${messageId}`);
    }

    // 8. Write explainability trace
    const tracePath = await writeExplainabilityTrace(email, result.sessionId, result);
    console.log(`Explainability trace: ${tracePath}`);

    summary.success = 1;
    summary.totalDurationMs = Date.now() - startTime;
  } catch (error) {
    summary.errors = 1;
    summary.totalDurationMs = Date.now() - startTime;
    summary.errorDetails.push({
      messageId,
      error: error instanceof Error ? error.message : String(error),
    });

    console.error(`Error processing ${messageId}: ${error instanceof Error ? error.message : String(error)}`);

    // Write trace with error information and partial result (if available)
    const partialResult = error instanceof ClassificationPipelineError ? error.partialResult : undefined;
    await writeExplainabilityTrace(
      email,
      tempSessionId,
      partialResult,
      error instanceof Error ? error : new Error(String(error))
    );
  } finally {
    // Always flush and close the interceptor
    await interceptor.close();
  }

  return summary;
}

/**
 * Process batch of unclassified emails
 *
 * @param limit - Maximum number of emails to process
 * @param config - Category configuration
 * @param dryRun - If true, skip persistence
 * @returns Processing summary
 */
export async function processBatchEmails(
  limit: number,
  config: CategoryConfiguration,
  dryRun: boolean
): Promise<ProcessingSummary> {
  const summary: ProcessingSummary = {
    totalEmails: 0,
    success: 0,
    errors: 0,
    totalDurationMs: 0,
    errorDetails: [],
  };

  const startTime = Date.now();

  try {
    // 1. Fetch unclassified emails
    logger.debug({ limit }, 'Fetching unclassified emails');
    const emails = await fetchUnclassifiedEmails(limit);

    summary.totalEmails = emails.length;
    console.log(`Found ${emails.length} emails to process\n`);

    if (emails.length === 0) {
      console.log('No unclassified emails found.');
      summary.totalDurationMs = Date.now() - startTime;
      return summary;
    }

    // 2. Initialize pipeline with test mode enabled
    const pipeline = new ClassificationPipeline(config, true);

    // 3. Create single session for entire batch
    const session = createClassificationSession(config.processingConfig, 'sequential', emails.length, true);

    // 4. Process each email with shared session
    const repoRoot = await findRepoRoot();
    const sessionDir = join(repoRoot, 'test-pipeline-results', session.id);
    await fs.mkdir(sessionDir, { recursive: true });

    for (let i = 0; i < emails.length; i++) {
      const email = emails[i];

      // Create console interceptor for this email
      const logPath = join(sessionDir, `${email.id}.log`);
      const interceptor = new ConsoleInterceptor(logPath);

      try {
        interceptor.start();
        logger.debug({ emailId: email.id, subject: email.subject }, 'Classifying email');
        const result = await pipeline.classifyWithSession(email, session, i);

        console.log(formatEmailOutput(email, result));

        if (!dryRun) {
          await saveClassificationResult(email.id, result);
        }

        await writeExplainabilityTrace(email, session.id, result);

        incrementSessionSuccess(session);
        summary.success++;
      } catch (error) {
        const errorMessage = error instanceof Error ? error.message : String(error);
        const stageName = error instanceof ClassificationPipelineError ? error.stage : 'pipeline';
        incrementSessionError(session, email.id, stageName, errorMessage, false);
        summary.errors++;
        summary.errorDetails.push({
          messageId: email.id,
          error: errorMessage,
        });

        console.error(`Error processing ${email.id}: ${errorMessage}`);

        // Write trace with error information and partial result (if available)
        const partialResult = error instanceof ClassificationPipelineError ? error.partialResult : undefined;
        await writeExplainabilityTrace(
          email,
          session.id,
          partialResult,
          error instanceof Error ? error : new Error(String(error))
        );
      } finally {
        // Always flush and close the interceptor
        await interceptor.close();
      }
    }

    // 5. Finalize session
    finalizeClassificationSession(session);

    summary.totalDurationMs = Date.now() - startTime;
  } catch (error) {
    console.error(`Fatal error in batch processing: ${error instanceof Error ? error.message : String(error)}`);
    throw error;
  }

  return summary;
}

